const formationGrids = {
  "3-1-4-2":   [[1], [5, 4, 6], [8], [2, 7, 11, 3], [9, 10]],
  "3-2-4-1":   [[1], [6, 5, 4], [2, 3], [10, 7, 8, 11], [9]],
  "3-3-3-1":   [[1], [6, 5, 4], [2, 8, 3], [10, 7, 11], [9]],
  "3-4-1-2":   [[1], [6, 5, 4], [2, 7, 8, 3], [9], [10, 11]],
  "3-4-2-1":   [[1], [6, 5, 4], [2, 7, 8, 3], [10, 11], [9]],
  "3-4-3":     [[1], [6, 5, 4], [2, 7, 8, 3], [10, 9, 11]],
  "3-5-2":     [[1], [6, 5, 4], [2, 7, 11, 8, 3], [10, 9]],
  "4-1-2-1-2": [[1], [2, 5, 6, 3], [4], [7, 11], [8], [10, 9]],
  "4-1-3-2":   [[1], [2, 5, 6, 3], [4], [7, 8, 11], [9, 10]],
  "4-1-4-1":   [[1], [2, 5, 6, 3], [4], [7, 8, 10, 11], [9]],
  "4-2-3-1":   [[1], [2, 5, 6, 3], [8, 4], [7, 10, 11], [9]],
  "4-3-3":     [[1], [2, 5, 6, 3], [7, 4, 8], [10, 9, 11]],
  "4-4-2":     [[1], [2, 5, 6, 3], [7, 4, 8, 11], [10, 9]],
  "4-5-1":     [[1], [2, 5, 6, 3], [7, 4, 10, 8, 11], [9]],
  "5-3-2":     [[1], [2, 6, 5, 4, 3], [7, 8, 11], [10, 9]],
  "5-4-1":     [[1], [2, 6, 5, 4, 3], [7, 8, 10, 11], [9]],
};

const positionMap = { "G": "Goalkeeper", "D": "Defender", "M": "Midfielder", "F": "Forward" };
const result = { teamHomeLineup: [], teamAwayLineup: [] };
const response = $input.all()[0].json.response;

response.forEach((teamData, index) => {
  const isHome = index === 0;
  const targetArray = isHome ? result.teamHomeLineup : result.teamAwayLineup;
  const formation = teamData.formation || "4-4-2";

  teamData.startXI.forEach((p, i) => {
    const gridStr = p.player.grid;
    let formationPlace = i + 1;
    let formationPosition = i + 1;

    if (gridStr) {
      const [row, col] = gridStr.split(':').map(Number);
      const rows = formationGrids[formation] || formationGrids["4-4-2"];
      const rowArr = rows[row - 1] || [];
      // Partner-API zählt Spalten von rechts nach links → umkehren
      formationPlace = rowArr[rowArr.length - col] ?? (i + 1);
      formationPosition = row;
    }

    targetArray.push({
      playerId: p.player.id,
      sport: "Football",
      position: positionMap[p.player.pos] ?? "Midfielder",
      jerseyNumber: p.player.number ?? null,
      status: "Start",
      formationPlace,
      formationPosition,
      numberOfGoals: 0,
      hasYellowCard: false,
      hasRedCard: false,
      isSubstituted: false
    });
  });

  teamData.substitutes.forEach((p) => {
    targetArray.push({
      playerId: p.player.id,
      sport: "Football",
      position: positionMap[p.player.pos] ?? "Midfielder",
      jerseyNumber: p.player.number ?? null,
      status: "Sub",
      formationPlace: 0,
      formationPosition: 0,
      numberOfGoals: 0,
      hasYellowCard: false,
      hasRedCard: false,
      isSubstituted: false
    });
  });
});

return [{ json: result }];
